def main():
    with open(CATALOG_PATH,"r",encoding="utf-8") as f: existing=json.load(f)
    existing_names={item["name_zh"] for item in existing}
    new_items=[item for item in BATCH12 if item["name_zh"] not in existing_names]
    merged=existing+new_items
    style_count={}
    for item in merged:
        s=item.get("style_tags",["unknown"])[0]; style_count[s]=style_count.get(s,0)+1
    with open(CATALOG_PATH,"w",encoding="utf-8") as f: json.dump(merged,f,ensure_ascii=False,indent=2)
    print(f"Current: {len(existing)}\nAdding: {len(new_items)}\nTotal: {len(merged)}")
    for s in sorted(style_count): print(f"  {s:<15}: {style_count[s]}")
    print("Done.")
if __name__=="__main__": main()
